import{_ as e,o as d,c as r,aj as o}from"./chunks/framework.RhfyOUxy.js";const p=JSON.parse('{"title":"Glossaire TopSolid FR / EN","description":"","frontmatter":{},"headers":[],"relativePath":"reference/glossaire.md","filePath":"reference/glossaire.md"}'),a={name:"reference/glossaire.md"};function i(s,t,n,c,l,m){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="glossaire-topsolid-fr-en" tabindex="-1">Glossaire TopSolid FR / EN <a class="header-anchor" href="#glossaire-topsolid-fr-en" aria-label="Permalink to &quot;Glossaire TopSolid FR / EN&quot;">​</a></h1><p>Mapping officiel des termes metier TopSolid (francais) vers les termes API (anglais). Valide par Julien (PM TopSolid Steel &amp; Design).</p><h2 id="proprietes-document-colonnes-pdm" tabindex="-1">Proprietes document (colonnes PDM) <a class="header-anchor" href="#proprietes-document-colonnes-pdm" aria-label="Permalink to &quot;Proprietes document (colonnes PDM)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>TopSolid FR</th><th>API EN</th><th>Methode API</th></tr></thead><tbody><tr><td><strong>Nom</strong></td><td>Name</td><td><code>IPdm.SetName</code> / <code>GetName</code></td></tr><tr><td><strong>Designation</strong></td><td>Description</td><td><code>IPdm.SetDescription</code> / <code>GetDescription</code></td></tr><tr><td><strong>Reference</strong></td><td>PartNumber</td><td><code>IPdm.SetPartNumber</code> / <code>GetPartNumber</code></td></tr><tr><td><strong>Fabricant</strong></td><td>Manufacturer</td><td><code>IPdm.SetManufacturer</code> / <code>GetManufacturer</code></td></tr><tr><td><strong>Reference fabricant</strong></td><td>ManufacturerPartNumber</td><td><code>IPdm.SetManufacturerPartNumber</code> / <code>GetManufacturerPartNumber</code></td></tr><tr><td><strong>Auteur</strong></td><td>Author</td><td><code>IPdm.SetAuthor</code> / <code>GetAuthor</code></td></tr><tr><td><strong>Proprietaire</strong></td><td>Owner</td><td><code>IPdm.GetOwner</code></td></tr><tr><td><strong>Code</strong></td><td>Code</td><td><code>IPdm.GetCode</code></td></tr><tr><td><strong>Commentaire</strong></td><td>Comment</td><td>Parametre systeme</td></tr></tbody></table><div class="danger custom-block"><p class="custom-block-title">Piege courant</p><p>&quot;Designation&quot; en TopSolid = <code>Description</code> dans l&#39;API. <strong>Pas</strong> <code>Name</code> !</p></div><h2 id="acces-direct-aux-proprietes-document-via-iparameters" tabindex="-1">Acces direct aux proprietes document (via IParameters) <a class="header-anchor" href="#acces-direct-aux-proprietes-document-via-iparameters" aria-label="Permalink to &quot;Acces direct aux proprietes document (via IParameters)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>TopSolid FR</th><th>Methode directe</th></tr></thead><tbody><tr><td>Nom</td><td><code>IParameters.GetNameParameter(docId)</code></td></tr><tr><td>Designation</td><td><code>IParameters.GetDescriptionParameter(docId)</code></td></tr><tr><td>Reference</td><td><code>IParameters.GetPartNumberParameter(docId)</code></td></tr><tr><td>Fabricant</td><td><code>IParameters.GetManufacturerParameter(docId)</code></td></tr><tr><td>Ref fabricant</td><td><code>IParameters.GetManufacturerPartNumberParameter(docId)</code></td></tr><tr><td>Auteur</td><td><code>IParameters.GetAuthorParameter(docId)</code></td></tr><tr><td>Revision majeure</td><td><code>IParameters.GetMajorRevisionParameter(docId)</code></td></tr><tr><td>Revision mineure</td><td><code>IParameters.GetMinorRevisionParameter(docId)</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Formules parametriques</p><p>On peut lier des proprietes entre elles avec <code>SetTextParameterizedValue</code> :</p><ul><li><code>[$PartNumber]</code> = Reference</li><li><code>[$Description]</code> = Designation</li><li><code>[$MajorRevision]</code> = Revision majeure</li><li><code>[$PartNumber][$MajorRevision]-[$Description]</code> = formule composee</li></ul></div><h2 id="proprietes-systeme-system-parameters" tabindex="-1">Proprietes systeme (System Parameters) <a class="header-anchor" href="#proprietes-systeme-system-parameters" aria-label="Permalink to &quot;Proprietes systeme (System Parameters)&quot;">​</a></h2><p>Accessibles via <code>GetParameters(docId)</code> + <code>GetFriendlyName(paramId)</code> + <code>GetRealValue/GetTextValue/...</code></p><h3 id="sur-piece-topprt" tabindex="-1">Sur piece (.TopPrt) <a class="header-anchor" href="#sur-piece-topprt" aria-label="Permalink to &quot;Sur piece (.TopPrt)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Nom systeme (EN)</th><th>TopSolid FR</th><th>Type</th><th>Unite</th></tr></thead><tbody><tr><td>Mass</td><td>Masse</td><td>Real</td><td>kg</td></tr><tr><td>Volume</td><td>Volume</td><td>Real</td><td>m3</td></tr><tr><td>Surface Area</td><td>Surface</td><td>Real</td><td>m2</td></tr><tr><td>Height</td><td>Hauteur</td><td>Real</td><td>m</td></tr><tr><td>Width</td><td>Largeur</td><td>Real</td><td>m</td></tr><tr><td>Length</td><td>Longueur</td><td>Real</td><td>m</td></tr><tr><td>Thickness</td><td>Epaisseur</td><td>Real</td><td>m</td></tr><tr><td>Box X/Y/Z Size</td><td>Dimensions boite</td><td>Real</td><td>m</td></tr><tr><td>Box X/Y/Z marged size</td><td>Dimensions brut</td><td>Real</td><td>m</td></tr><tr><td>Stock Marged Height/Width/Length</td><td>Dimensions brut stock</td><td>Real</td><td>m</td></tr><tr><td>Principal X/Y/Z Moment</td><td>Moments d&#39;inertie</td><td>Real</td><td>kg.mm2</td></tr><tr><td>Sheet Metal</td><td>Tolerie</td><td>Boolean</td><td>—</td></tr><tr><td>Unfoldable Shape</td><td>Forme depliable</td><td>Boolean</td><td>—</td></tr><tr><td>Bends Number</td><td>Nombre de plis</td><td>Integer</td><td>—</td></tr><tr><td>Perimeter (Unfolding)</td><td>Perimetre deplie</td><td>Real</td><td>m</td></tr><tr><td>Surface Area (Unfolding)</td><td>Surface depliee</td><td>Real</td><td>m2</td></tr><tr><td>Box Width/Length (Unfolding)</td><td>Dimensions mise a plat</td><td>Real</td><td>m</td></tr></tbody></table><h3 id="sur-assemblage-topasm" tabindex="-1">Sur assemblage (.TopAsm) <a class="header-anchor" href="#sur-assemblage-topasm" aria-label="Permalink to &quot;Sur assemblage (.TopAsm)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Nom systeme (EN)</th><th>TopSolid FR</th><th>Type</th></tr></thead><tbody><tr><td>Mass</td><td>Masse totale</td><td>Real</td></tr><tr><td>Volume</td><td>Volume total</td><td>Real</td></tr><tr><td>Surface Area</td><td>Surface totale</td><td>Real</td></tr><tr><td>Part Count</td><td>Nombre de pieces</td><td>Integer</td></tr><tr><td>Principal X/Y/Z Moment</td><td>Moments d&#39;inertie</td><td>Real</td></tr><tr><td>Type for BOM</td><td>Type nomenclature</td><td>Enumeration</td></tr></tbody></table><h3 id="sur-tout-document" tabindex="-1">Sur tout document <a class="header-anchor" href="#sur-tout-document" aria-label="Permalink to &quot;Sur tout document&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Nom systeme (EN)</th><th>TopSolid FR</th><th>Type</th></tr></thead><tbody><tr><td>Author</td><td>Auteur</td><td>Text</td></tr><tr><td>Name</td><td>Nom</td><td>Text</td></tr><tr><td>Description</td><td>Designation</td><td>Text</td></tr><tr><td>Part Number</td><td>Reference</td><td>Text</td></tr><tr><td>Manufacturer</td><td>Fabricant</td><td>Text</td></tr><tr><td>Standard</td><td>Standard</td><td>Enumeration</td></tr><tr><td>Major Revision</td><td>Revision majeure</td><td>Text</td></tr><tr><td>Minor Revision</td><td>Revision mineure</td><td>Text</td></tr><tr><td>Creation Date</td><td>Date creation</td><td>DateTime</td></tr><tr><td>Modification Date</td><td>Date modification</td><td>DateTime</td></tr><tr><td>Universal Identifier</td><td>Identifiant universel</td><td>Unclassified</td></tr><tr><td>Create new universal identifier at copy</td><td>Nouvel ID a la copie</td><td>Boolean</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Astuce</p><p>Les parametres systeme ont un <code>$</code> dans leur nom interne (<code>GetName</code>). Utiliser <code>GetFriendlyName</code> pour le nom lisible (Mass, Volume, etc.).</p></div><h2 id="operations-pdm" tabindex="-1">Operations PDM <a class="header-anchor" href="#operations-pdm" aria-label="Permalink to &quot;Operations PDM&quot;">​</a></h2><table tabindex="0"><thead><tr><th>TopSolid FR</th><th>API EN</th><th>Methode</th><th>Notes</th></tr></thead><tbody><tr><td>Mise au coffre</td><td>CheckIn</td><td><code>IPdm.CheckIn(pdmId, true)</code></td><td>Archive la revision</td></tr><tr><td>Sorti de coffre</td><td>CheckOut</td><td><code>IPdm.CheckOut(pdmId)</code></td><td>Reserve pour modification</td></tr><tr><td>En modification</td><td>EnsureIsDirty</td><td><code>IDocuments.EnsureIsDirty(ref docId)</code></td><td><strong>Le docId change (ref) !</strong></td></tr><tr><td>Sauvegarder</td><td>Save</td><td><code>IPdm.Save(pdmId, true)</code></td><td>Obligatoire apres EndModification</td></tr><tr><td>Document modifie ?</td><td>IsDirty</td><td><code>IPdm.IsDirty(pdmId)</code></td><td>True si non sauvegarde</td></tr><tr><td>Rechercher par nom</td><td>SearchByName</td><td><code>IPdm.SearchDocumentByName(projId, name)</code></td><td>Retourne List</td></tr><tr><td>Deplacer documents</td><td>MoveSeveral</td><td><code>IPdm.MoveSeveral(list, destId)</code></td><td>Batch move</td></tr><tr><td>Projets references</td><td>GetReferencedProjects</td><td><code>IPdm.GetReferencedProjects(projId)</code></td><td>Bibliotheques liees</td></tr><tr><td>Contenu dossier</td><td>GetConstituents</td><td><code>IPdm.GetConstituents(id, out folders, out docs)</code></td><td>Recursif</td></tr><tr><td>Creer document</td><td>CreateDocument</td><td><code>IPdm.CreateDocument(parentId, &quot;.TopPrt&quot;, true)</code></td><td>Par type</td></tr><tr><td>Import fichier</td><td>ImportFile</td><td><code>IPdm.ImportFile(path, projId, name)</code></td><td>Raccourci direct</td></tr><tr><td>Import avec options</td><td>ImportWithOptions</td><td><code>IDocuments.ImportWithOptions(idx, opts, path, ...)</code></td><td>Parametre fin</td></tr></tbody></table><h2 id="revisions" tabindex="-1">Revisions <a class="header-anchor" href="#revisions" aria-label="Permalink to &quot;Revisions&quot;">​</a></h2><table tabindex="0"><thead><tr><th>TopSolid FR</th><th>API EN</th><th>Methode</th></tr></thead><tbody><tr><td>Revision majeure</td><td>MajorRevision</td><td><code>IPdm.GetMajorRevisions(pdmId)</code></td></tr><tr><td>Revision mineure</td><td>MinorRevision</td><td><code>IPdm.GetMinorRevisions(majorRevId)</code></td></tr><tr><td>Derniere revision</td><td>LastMajorRevision</td><td><code>IPdm.GetLastMajorRevision(pdmId)</code></td></tr><tr><td>Ouvrir une revision</td><td>OpenMinorRevision</td><td><code>IPdm.OpenMinorRevision(minorRevId, readOnly)</code></td></tr><tr><td>Cas d&#39;emploi</td><td>BackReferences</td><td><code>IPdm.SearchMajorRevisionBackReferences(projId, majorRev)</code></td></tr><tr><td>Etat cycle de vie</td><td>LifeCycleMainState</td><td><code>IPdm.GetMajorRevisionLifeCycleMainState(majorRev)</code></td></tr><tr><td>Texte revision</td><td>RevisionText</td><td><code>IPdm.GetMajorRevisionText(majorRev)</code></td></tr><tr><td>Preview document</td><td>PreviewBitmap</td><td><code>IPdm.GetMinorRevisionPreviewBitmap(minorRev)</code></td></tr></tbody></table><h2 id="types-de-documents" tabindex="-1">Types de documents <a class="header-anchor" href="#types-de-documents" aria-label="Permalink to &quot;Types de documents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Extension</th><th>TopSolid FR</th><th>Utilisation</th></tr></thead><tbody><tr><td><code>.TopPrt</code></td><td>Piece</td><td>Piece 3D modelisee</td></tr><tr><td><code>.TopAsm</code></td><td>Assemblage</td><td>Ensemble de pieces</td></tr><tr><td><code>.TopDft</code></td><td>Mise en plan</td><td>Dessin 2D (vues, cotation)</td></tr><tr><td><code>.TopMat</code></td><td>Materiau</td><td>Definition materiau (acier, alu...)</td></tr><tr><td><code>.TopTex</code></td><td>Texture</td><td>Image PBR (albedo, roughness, normal...)</td></tr><tr><td><code>.TopPrd</code></td><td>Propriete utilisateur</td><td>Enumeration custom (Type production, Type composant...)</td></tr><tr><td><code>.TopFam</code></td><td>Famille</td><td>Document avec catalogue d&#39;instances</td></tr></tbody></table><h2 id="mode-virtuel" tabindex="-1">Mode virtuel <a class="header-anchor" href="#mode-virtuel" aria-label="Permalink to &quot;Mode virtuel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>TopSolid FR</th><th>API EN</th><th>Methode</th></tr></thead><tbody><tr><td>Document virtuel</td><td>VirtualDocument</td><td><code>IDocuments.IsVirtualDocument(docId)</code></td></tr><tr><td>Activer mode virtuel</td><td>SetVirtualDocumentMode</td><td><code>IDocuments.SetVirtualDocumentMode(docId, true)</code></td></tr><tr><td>Piece derivee</td><td>DerivedPart</td><td><code>IParts.IsDerivedPart(docId)</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Le mode virtuel empeche les mises a jour automatiques. Utile pour les composants standards dans les bibliotheques.</p></div><h2 id="interfaces" tabindex="-1">Interfaces <a class="header-anchor" href="#interfaces" aria-label="Permalink to &quot;Interfaces&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Interface</th><th>Termes FR acceptes</th><th>Methodes cles</th></tr></thead><tbody><tr><td>IPdm</td><td>PDM, coffre, projet</td><td>GetName, SetDescription, Save, CheckIn</td></tr><tr><td>IDocuments</td><td>Document, ouvrir, fermer</td><td>EditedDocument, Open, Import, Export</td></tr><tr><td>IParameters</td><td>Parametre, cote, valeur</td><td>GetParameters, GetRealValue, SetTextValue</td></tr><tr><td>IElements</td><td>Element, entite, nommer</td><td>GetFriendlyName, SearchByName, SetDescription</td></tr><tr><td>IFamilies</td><td>Famille, catalogue, code</td><td>IsFamily, GetCatalogColumnParameters</td></tr><tr><td>IAssemblies</td><td>Assemblage, inclusion, occurrence</td><td>IsAssembly, GetParts, GetOccurrenceDefinition</td></tr><tr><td>IParts</td><td>Piece, masse, inertie</td><td>IsDerivedPart, GetMassPropertyManagement</td></tr><tr><td>ICoatings</td><td>Revetement, <strong>peinture</strong>, <strong>traitement</strong></td><td>SetColor, GetColor</td></tr><tr><td>IShapes</td><td>Forme, solide, tole</td><td>GetShapes, GetShapeType, GetShapeVolume</td></tr><tr><td>ISketches2D</td><td>Esquisse, profil, sketch</td><td>GetSketches, CreateSketchIn3D</td></tr><tr><td>IOperations</td><td>Operation, feature, arbre</td><td>GetOperations, GetChildren</td></tr><tr><td>IDraftings</td><td>Mise en plan, plan, draft</td><td>IsDrafting, GetDraftingViews, GetPageCount</td></tr><tr><td>IBoms</td><td>Nomenclature, <strong>rafale</strong>, fiche, BOM</td><td>IsBom, GetRowContents, GetRootRow</td></tr><tr><td>ITables</td><td>Tableaux (en mise en plan)</td><td>GetDraftTables, GetDraftTableCellText</td></tr><tr><td>IUnfoldings</td><td><strong>Mise a plat</strong>, depliage</td><td>IsUnfolding, GetBendFeatures</td></tr><tr><td>ITextures</td><td>Texture, image PBR</td><td>SetCategory, SetPicture, SetTextureScale</td></tr><tr><td>IMaterials</td><td>Materiau, matiere</td><td>GetDensity (v7.16+)</td></tr><tr><td>IVisualization3D</td><td>Vue 3D, viewport</td><td>GetActiveView, GetViewRectangle</td></tr><tr><td>IAnnotations</td><td>Annotation, cotation, <strong>cote 3D</strong></td><td>GetAnnotationType</td></tr><tr><td>IUser</td><td>Utilisateur, selection</td><td>Ask* (selection interactive dans TopSolid)</td></tr></tbody></table><h2 id="geometrie-modelisation" tabindex="-1">Geometrie / Modelisation <a class="header-anchor" href="#geometrie-modelisation" aria-label="Permalink to &quot;Geometrie / Modelisation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>API EN</th><th>TopSolid FR</th></tr></thead><tbody><tr><td>Profile</td><td>Profil, <strong>section</strong>, <strong>contour</strong></td></tr><tr><td>Loft / Lofted</td><td><strong>Lissage</strong> ou <strong>gabarit</strong></td></tr><tr><td>Pattern</td><td><strong>Motif</strong> (repetition)</td></tr><tr><td>Revolution</td><td>Revolution, <strong>piece tournee</strong></td></tr><tr><td>Extrusion</td><td>Extrusion, <strong>extrude</strong></td></tr><tr><td>Shell</td><td>Coque</td></tr><tr><td>Sheet</td><td>Tole</td></tr><tr><td>Unfolding</td><td><strong>Mise a plat</strong>, depliage</td></tr><tr><td>Bend</td><td>Pli, pliage</td></tr><tr><td>Enclosing Box</td><td>Boite englobante, brut</td></tr></tbody></table><h2 id="parametres-avances" tabindex="-1">Parametres avances <a class="header-anchor" href="#parametres-avances" aria-label="Permalink to &quot;Parametres avances&quot;">​</a></h2><table tabindex="0"><thead><tr><th>API EN</th><th>TopSolid FR</th><th>Usage</th></tr></thead><tbody><tr><td>SmartReal / SmartText</td><td>Parametrise, formule</td><td>Valeur avec formule ou lien</td></tr><tr><td>UnitType</td><td>Type d&#39;unite</td><td>Length, Angle, Mass, etc.</td></tr><tr><td>Driver</td><td><strong>Pilote</strong></td><td>Parametre qui pilote une famille</td></tr><tr><td>Working stage</td><td><strong>Etape courante</strong></td><td>Position dans l&#39;arbre de construction</td></tr><tr><td>UserEnumeration</td><td>Enumeration utilisateur</td><td>Propriete custom (.TopPrd)</td></tr><tr><td>ParameterType</td><td>Type de parametre</td><td>Real=1, Integer=2, Boolean=3, Text=4, DateTime=5, Family=6, Code=7, Enumeration=8, UserEnumeration=9</td></tr></tbody></table><h2 id="proprietes-utilisateur-topprd" tabindex="-1">Proprietes utilisateur (.TopPrd) <a class="header-anchor" href="#proprietes-utilisateur-topprd" aria-label="Permalink to &quot;Proprietes utilisateur (.TopPrd)&quot;">​</a></h2><p>Workflow complet pour affecter une propriete utilisateur :</p><ol><li><code>IPdm.GetReferencedProjects(projId)</code> — trouver les projets references</li><li><code>IPdm.SearchDocumentByName(refProj, &quot;Type Composant&quot;)</code> — chercher le .TopPrd</li><li><code>IPdm.GetType(objId, out type)</code> — filtrer par <code>.TopPrd</code></li><li><code>IParameters.CreateUserPropertyParameter(docId, propDocId)</code> — creer le parametre</li><li><code>IParameters.GetUserEnumerationDefinition(paramId)</code> — lire la definition</li><li><code>IParameters.GetUserEnumerationValues(defId, out values, out texts)</code> — valeurs possibles</li><li><code>IParameters.SetUserEnumerationValue(paramId, valueIndex)</code> — affecter une valeur</li></ol><h2 id="concepts-metier" tabindex="-1">Concepts metier <a class="header-anchor" href="#concepts-metier" aria-label="Permalink to &quot;Concepts metier&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Terme TopSolid</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Rafale</strong></td><td>Generation par lot : un plan ou une mise a plat par ligne de nomenclature</td></tr><tr><td><strong>Liasse de plans</strong></td><td>Collection structuree de mises en plan</td></tr><tr><td><strong>Modele</strong></td><td>Template reutilisable (fonctionne pour tous types de documents)</td></tr><tr><td><strong>Nomenclature filtree</strong></td><td>BOM avec filtre (toles, profiles, achetes...)</td></tr><tr><td><strong>Ensemble de projection</strong></td><td>Definit quoi projeter dans une mise en plan</td></tr><tr><td><strong>Propriete utilisateur</strong></td><td>Propriete custom stockee dans .TopPrd (ex: Type production)</td></tr><tr><td><strong>Propriete d&#39;occurrence</strong></td><td>Propriete ajoutee/surchargee sur une occurrence d&#39;assemblage</td></tr><tr><td><strong>Cas d&#39;emploi</strong></td><td>Where-used — dans quels documents cette piece est utilisee</td></tr><tr><td><strong>Document virtuel</strong></td><td>Document qui ne se met pas a jour automatiquement</td></tr><tr><td><strong>Piece derivee</strong></td><td>Piece creee par derivation d&#39;une autre (lien parametrique)</td></tr><tr><td><strong>Driver / Pilote</strong></td><td>Parametre qui pilote les instances d&#39;une famille</td></tr><tr><td><strong>Catalogue famille</strong></td><td>Tableau des instances (codes x colonnes/drivers)</td></tr><tr><td><strong>Composant standard</strong></td><td>Piece de bibliotheque non modifiable (vis, ecrou...)</td></tr><tr><td><strong>Inclusion</strong></td><td>Composant place dans un assemblage</td></tr><tr><td><strong>Occurrence</strong></td><td>Instance d&#39;une inclusion dans l&#39;assemblage</td></tr></tbody></table>',37)])])}const h=e(a,[["render",i]]);export{p as __pageData,h as default};
